# factor → NUMBER | '(' expr ')'
def factor(self) -> float:
    tok = self.peek()
    if tok is None:
        raise ValueError("Unexpected end of expression")
    if tok == '(':
        self.consume('(')
        result = self.expr()
        self.consume(')')
        return result
    # Must be a number
    self.consume()
    return float(tok)

